const msg = $input.first().json;
const text = (msg.message?.text || '').trim();
const chatId = String(msg.message?.chat?.id || '');

const state = $getWorkflowStaticData('global');
if (!state.pending_selections) state.pending_selections = {};

// Clean up expired entries (>5 min)
const now = Date.now();
for (const uid of Object.keys(state.pending_selections)) {
  if (now - state.pending_selections[uid].timestamp > 5 * 60 * 1000) {
    delete state.pending_selections[uid];
  }
}

if (text === '/start' || text === '/help') {
  return [{ json: { route: 'welcome', chatId } }];
}

const pending = state.pending_selections[chatId];
if (pending) {
  const num = parseInt(text, 10);
  if (!isNaN(num) && num >= 1 && num <= pending.options.length) {
    const selectionData = {
      chosen: pending.options[num - 1],
      room: pending.room,
      entity_id: pending.entity_id,
      library: pending.library,
      season: pending.season || null,
      episode: pending.episode || null
    };
    delete state.pending_selections[chatId];
    return [{ json: { route: 'selection', chatId, selectionData } }];
  }
  if (text === '0' || text.toLowerCase() === 'cancel') {
    delete state.pending_selections[chatId];
    return [{ json: { route: 'direct_reply', chatId, speech: 'Selection cancelled.' } }];
  }
  const isCommand = /^(play|pause|resume|stop)\b/i.test(text) || text.startsWith('/');
  if (!isCommand) {
    return [{ json: { route: 'direct_reply', chatId, speech: `Please reply with a number between 1 and ${pending.options.length}, or 0 to cancel.` } }];
  }
  delete state.pending_selections[chatId];
}

let command = text;
if (command.startsWith('/')) {
  const spaceIdx = command.indexOf(' ');
  if (spaceIdx > 0) command = command.substring(1);
}

if (/^(pause|resume|stop)\b/i.test(command)) {
  return [{ json: { route: 'other', text: command, chatId } }];
}

return [{ json: { route: 'play', text: command, chatId } }];

const input = $input.first().json;
const sel = input.selectionData;
const chatId = input.chatId;

if (!sel || !sel.chosen) {
  return [{ json: { chatId, speech: 'Sorry, I could not find your selection. Please try again.' } }];
}

const chosen = sel.chosen;
const libraryMap = { movies: 'Movies', tv: 'TV Shows', p90x: 'P90X', youtube: 'YouTube' };
const contentTypeMap = { movies: 'movie', tv: 'EPISODE', p90x: 'video', youtube: 'video' };
const libraryName = libraryMap[sel.library] || 'Movies';
const haContentType = contentTypeMap[sel.library] || 'movie';

let contentId;
if (sel.library === 'tv') {
  contentId = { library_name: libraryName, show_name: chosen.title };
  if (sel.season) contentId.season_number = sel.season;
  if (sel.episode) contentId.episode_number = sel.episode;
} else {
  contentId = { library_name: libraryName, title: chosen.title };
  if (chosen.year) contentId.year = chosen.year;
}

let entityId = sel.entity_id;
if (entityId === 'all') {
  entityId = [
    'media_player.plex_plex_for_samsung_tv_2021',
    'media_player.plex_plex_for_samsung_tv_2021_2',
    'media_player.master_tv'
  ];
}

return [{ json: {
  chatId,
  entity_id: entityId,
  ha_content_id: JSON.stringify(contentId),
  ha_content_type: haContentType,
  title: chosen.title,
  year: chosen.year || null,
  room: sel.room
} }];

const response = $input.first().json;
const chatId = $('Build Claude Prompt').first().json.chatId;

if (response.error) {
  return [{ json: { chatId, speech: 'Sorry, I had trouble understanding that. Please try again.', resultType: 'not_found' } }];
}

let claudeText = '';
if (response.content && response.content.length > 0) {
  claudeText = response.content[0].text.trim();
}

if (!claudeText) {
  return [{ json: { chatId, speech: 'Sorry, I did not get a response. Please try again.', resultType: 'not_found' } }];
}

let parsed;
try {
  parsed = JSON.parse(claudeText);
} catch (e) {
  const jsonMatch = claudeText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[1].trim());
  } else {
    const objMatch = claudeText.match(/\{[\s\S]*\}/);
    if (objMatch) {
      parsed = JSON.parse(objMatch[0]);
    } else {
      return [{ json: { chatId, speech: 'Sorry, I could not process that command.', resultType: 'not_found' } }];
    }
  }
}

if (parsed.action === 'error') {
  return [{ json: { chatId, speech: parsed.error || 'Sorry, I did not understand. Please try again.', resultType: 'not_found' } }];
}

if (parsed.action !== 'play') {
  return [{ json: { chatId, speech: 'Unexpected action. Please try again.', resultType: 'not_found' } }];
}

let entityId = parsed.entity_id;
if (entityId === 'all') {
  entityId = [
    'media_player.plex_plex_for_samsung_tv_2021',
    'media_player.plex_plex_for_samsung_tv_2021_2',
    'media_player.master_tv'
  ];
}

const searchQuery = encodeURIComponent(parsed.title);

return [{ json: {
  chatId,
  title: parsed.title,
  year_hint: parsed.year_hint || null,
  season: parsed.season || null,
  episode: parsed.episode || null,
  library: parsed.library || 'movies',
  room: parsed.room,
  entity_id: entityId,
  searchQuery
} }];

const plexResponse = $input.first().json;
const prev = $('Parse Claude + Prep Search').first().json;
const chatId = prev.chatId;

const hubs = plexResponse?.MediaContainer?.Hub || [];
const libraryTypeMap = { movies: 'movie', tv: 'show', p90x: 'movie', youtube: 'movie' };
const targetType = libraryTypeMap[prev.library] || 'movie';

let matches = [];
for (const hub of hubs) {
  if (hub.type === targetType && hub.Metadata) {
    for (const item of hub.Metadata) {
      matches.push({
        title: item.title,
        year: item.year || null,
        ratingKey: item.ratingKey
      });
    }
  }
}

if (prev.year_hint && matches.length > 1) {
  matches.sort((a, b) => {
    const aMatch = a.year === prev.year_hint ? 0 : 1;
    const bMatch = b.year === prev.year_hint ? 0 : 1;
    return aMatch - bMatch;
  });
  if (matches[0].year === prev.year_hint) {
    matches = [matches[0]];
  }
}

if (matches.length === 0) {
  return [{ json: { chatId, resultType: 'not_found', speech: `I could not find "${prev.title}" in your Plex library. Check the title and try again.` } }];
}

if (matches.length === 1) {
  const match = matches[0];
  const libraryMap = { movies: 'Movies', tv: 'TV Shows', p90x: 'P90X', youtube: 'YouTube' };
  const contentTypeMap = { movies: 'movie', tv: 'EPISODE', p90x: 'video', youtube: 'video' };
  const libraryName = libraryMap[prev.library] || 'Movies';
  const haContentType = contentTypeMap[prev.library] || 'movie';

  let contentId;
  if (prev.library === 'tv') {
    contentId = { library_name: libraryName, show_name: match.title };
    if (prev.season) contentId.season_number = prev.season;
    if (prev.episode) contentId.episode_number = prev.episode;
  } else {
    contentId = { library_name: libraryName, title: match.title };
    if (match.year) contentId.year = match.year;
  }

  return [{ json: {
    chatId, resultType: 'play_now',
    entity_id: prev.entity_id,
    ha_content_id: JSON.stringify(contentId),
    ha_content_type: haContentType,
    title: match.title,
    year: match.year,
    room: prev.room
  } }];
}

const options = matches.slice(0, 8);
const state = $getWorkflowStaticData('global');
if (!state.pending_selections) state.pending_selections = {};
state.pending_selections[chatId] = {
  room: prev.room,
  entity_id: prev.entity_id,
  library: prev.library,
  season: prev.season,
  episode: prev.episode,
  options,
  timestamp: Date.now()
};

let msg = `I found ${matches.length} matches for "${prev.title}". Which one?\n\n`;
options.forEach((opt, i) => {
  const yearStr = opt.year ? ` (${opt.year})` : '';
  msg += `${i + 1}. ${opt.title}${yearStr}\n`;
});
msg += '\nReply with a number, or 0 to cancel.';

return [{ json: { chatId, resultType: 'options', speech: msg } }];

const haResponse = $input.first().json;
let title, room, chatId, year;

try {
  const data = $('Resolve Selection').first().json;
  title = data.title;
  room = data.room;
  chatId = data.chatId;
  year = data.year;
} catch (e) {
  try {
    const data = $('Handle Results').first().json;
    title = data.title;
    room = data.room;
    chatId = data.chatId;
    year = data.year;
  } catch (e2) {
    chatId = $('Process Message').first().json.chatId;
    title = 'your media';
    room = 'unknown';
    year = null;
  }
}

const isAll = room === 'all';
const haFailed = haResponse.error || haResponse.statusCode >= 400;

if (haFailed) {
  const errorMsg = haResponse.error?.message || haResponse.error?.stack || '';
  const isTimeout = errorMsg.includes('ReadTimeout') || errorMsg.includes('timed out') || errorMsg.includes('timeout') || errorMsg.includes('ETIMEDOUT');
  if (isTimeout) {
    const where = isAll ? 'on all TVs' : `in the ${room}`;
    return [{ json: { chatId, speech: `Playing ${title}${year ? ' (' + year + ')' : ''} ${where}. Playback should start shortly.` } }];
  }
  const target = isAll ? 'all TVs' : `the ${room} TV`;
  return [{ json: { chatId, speech: `Sorry, I could not play on ${target}. Home Assistant returned an error.` } }];
}

const where = isAll ? 'on all TVs' : (room ? `in the ${room}` : '');
const yearStr = year ? ` (${year})` : '';
return [{ json: { chatId, speech: `Now playing ${title}${yearStr} ${where}.` } }];

const items = $input.all();
const data = items[0].json;

// Determine which entity to check
let checkEntityId;
let isAllTVs = false;

if (Array.isArray(data.entity_id)) {
  // "all TVs" mode - pick first entity to check availability
  checkEntityId = data.entity_id[0];
  isAllTVs = true;
} else {
  checkEntityId = data.entity_id;
}

// Pass through all original data plus the check entity
return [{ json: {
  ...data,
  checkEntityId,
  isAllTVs
} }];

const haResponse = $input.first().json;
const prev = $('Prep Entity Check').first().json;

// Check if the entity is available
const state = haResponse.state;
const gotError = haResponse.error || haResponse.statusCode === 404;
const isUnavailable = gotError || state === 'unavailable';

if (isUnavailable) {
  // Build a friendly error message
  let speech;
  if (prev.isAllTVs) {
    speech = "No Plex clients are available. Please open the Plex app on at least one TV and try again.";
  } else {
    const roomNames = {
      'media_player.plex_plex_for_samsung_tv_2021': 'living room',
      'media_player.plex_plex_for_samsung_tv_2021_2': 'boys room',
      'media_player.master_tv': 'master bedroom'
    };
    const roomName = roomNames[prev.checkEntityId] || prev.room || 'selected';
    speech = `The ${roomName} TV isn't running Plex. Please open the Plex app and try again.`;
  }

  return [{ json: {
    chatId: prev.chatId,
    speech,
    entityReady: false
  } }];
}

// Entity is available - pass through original play data
return [{ json: {
  ...prev,
  entityReady: true
} }];
